// Парсим JSON-ответ агента
const raw = $input.first().json.output || '';
let parsed;
try {
  // Убираем возможные markdown-обёртки
  const clean = raw.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  parsed = JSON.parse(clean);
} catch(e) {
  // Если не смогли распарсить — возвращаем raw как USER_MESSAGE
  parsed = {
    USER_MESSAGE: raw,
    ADMIN_MESSAGE: '',
    SHEET_UPDATE: {},
    NEXT_STAGE: $('Подготовка контекста').item.json.current_stage
  };
}

return [{
  json: {
    USER_MESSAGE: parsed.USER_MESSAGE || '',
    ADMIN_MESSAGE: parsed.ADMIN_MESSAGE || '',
    SHEET_UPDATE: parsed.SHEET_UPDATE || {},
    NEXT_STAGE: parsed.NEXT_STAGE || 'START',
    // Прокидываем нужные поля для следующих нод
    cuid: $('Подготовка контекста').item.json.cuid,
    admin_chat_id: $('Подготовка контекста').item.json.admin_chat_id,
    telegram_chat_id: $('Telegram Trigger').item.json.message.chat.id,
    user_message_text: $('Edit Fields').item.json.text,
    old_history: $('Подготовка контекста').item.json.history_of_messages
  }
}];

// Собираем объект для обновления Google Sheets
const sheetUpdate = $json.SHEET_UPDATE || {};
const oldHistory = $json.old_history || '';
const userMsg = $json.user_message_text || '';
const botMsg = $json.USER_MESSAGE || '';

// Обновляем историю сообщений
const newHistory = oldHistory 
  ? `${oldHistory}\n---\nПользователь: ${userMsg}\nНиколай: ${botMsg}`
  : `Пользователь: ${userMsg}\nНиколай: ${botMsg}`;

return [{
  json: {
    cuid: $json.cuid,
    last_time_ask: new Date().toISOString(),
    history_of_messages: newHistory,
    ...sheetUpdate
  }
}];

